import Navbar from "@/app/components/Navbar";
import Footer from "@/app/components/Footer";
import SearchBar from "@/app/components/SearchBar";
import JobCard from "@/app/components/JobCard";
import { getJobs } from "@/app/actions/jobs";
import { prisma } from "@/lib/prisma";

const INDUSTRIES = [
    { name: "Công nghệ Thông tin", slug: "cong-nghe-thong-tin" },
    { name: "Tài chính - Ngân hàng", slug: "tai-chinh-ngan-hang" },
    { name: "Thương mại điện tử", slug: "thuong-mai-dien-tu" },
    { name: "Marketing - Truyền thông", slug: "marketing-truyen-thong" },
    { name: "Nhân sự", slug: "nhan-su" },
    { name: "Kế toán - Tài chính", slug: "ke-toan-tai-chinh" },
    { name: "Bán lẻ - Dịch vụ", slug: "ban-le-dich-vu" },
    { name: "Sản xuất - Chế biến", slug: "san-xuat-che-bien" },
    { name: "Xây dựng", slug: "xay-dung" },
    { name: "Y tế - Chăm sóc sức khỏe", slug: "y-te-cham-soc-suc-khoe" },
    { name: "Du lịch - Khách sạn", slug: "du-lich-khach-san" },
    { name: "Giáo dục - Đào tạo", slug: "gd-dao-tao" },
    { name: "Kiến trúc - Thiết kế", slug: "kien-truc-thiet-ke" },
    { name: "Pháp lý", slug: "phap-luat" },
    { name: "Vận tải - Logistics", slug: "van-tai-logistics" },
];

const LOCATIONS = ["Hà Nội", "TP.HCM", "Đà Nẵng", "Cần Thơ", "Remote"];

export default async function JobsPage({
    searchParams,
}: {
    searchParams: Promise<{ q?: string; loc?: string; type?: string; industry?: string }>;
}) {
    const params = await searchParams;

    // Get industry filter
    let industryId = undefined;
    if (params.industry) {
        const industry = await prisma.industry.findUnique({
            where: { slug: params.industry }
        });
        if (industry) {
            industryId = industry.id;
        }
    }

    const jobs = await getJobs({
        q: params.q,
        loc: params.loc,
        type: params.type,
        industryId: industryId,
        status: "ACTIVE"
    }).catch(() => []);

    const currentIndustry = params.industry
        ? INDUSTRIES.find(i => i.slug === params.industry)?.name
        : null;

    return (
        <div style={{ minHeight: "100vh", display: "flex", flexDirection: "column" }}>
            <Navbar />

            {/* Sub-header */}
            <div style={{ background: "linear-gradient(135deg, #F0F9FF, #E0F2FE)", borderBottom: "1.5px solid var(--border)", padding: "2.5rem 0" }}>
                <div className="container-xl">
                    <h1 style={{ fontSize: "clamp(1.5rem, 3vw, 2rem)", fontWeight: 800, color: "var(--text)", marginBottom: "1.25rem" }}>
                        Tìm kiếm việc làm
                        {params.q && <span style={{ color: "var(--primary)" }}> &ldquo;{params.q}&rdquo;</span>}
                        {currentIndustry && <span style={{ color: "var(--cta)" }}> - {currentIndustry}</span>}
                    </h1>
                    <SearchBar size="lg" />
                </div>
            </div>

            <main className="section-sm" style={{ flex: 1, background: "var(--bg)" }}>
                <div className="container-xl">
                    <div style={{ display: "grid", gridTemplateColumns: "260px 1fr", gap: "2rem", alignItems: "flex-start" }}>
                        {/* Sidebar */}
                        <aside>
                            {/* Industries */}
                            <div className="card" style={{ padding: "1.5rem", marginBottom: "1.25rem" }}>
                                <h3 style={{ fontSize: "0.9375rem", fontWeight: 700, marginBottom: "1rem", display: "flex", alignItems: "center", gap: "0.5rem" }}>
                                    <svg width="16" height="16" fill="none" stroke="var(--primary)" strokeWidth="2" viewBox="0 0 24 24">
                                        <path strokeLinecap="round" strokeLinejoin="round" d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" />
                                    </svg>
                                    Ngành nghề
                                </h3>
                                <div style={{ display: "flex", flexDirection: "column", gap: "0.25rem" }}>
                                    <label style={{ display: "flex", alignItems: "center", gap: "0.5rem", cursor: "pointer", padding: "0.4rem 0" }}>
                                        <input
                                            type="radio"
                                            name="industry"
                                            checked={!params.industry}
                                            onChange={() => {
                                                const url = new URL(window.location.href);
                                                url.searchParams.delete("industry");
                                                window.location.href = url.toString();
                                            }}
                                            style={{ accentColor: "var(--primary)" }}
                                        />
                                        <span style={{ fontSize: "0.9rem", color: "var(--text)" }}>Tất cả ngành</span>
                                    </label>
                                    {INDUSTRIES.map((cat) => (
                                        <label key={cat.slug} style={{ display: "flex", alignItems: "center", gap: "0.5rem", cursor: "pointer", padding: "0.4rem 0" }}>
                                            <input
                                                type="radio"
                                                name="industry"
                                                checked={params.industry === cat.slug}
                                                onChange={() => {
                                                    const url = new URL(window.location.href);
                                                    url.searchParams.set("industry", cat.slug);
                                                    window.location.href = url.toString();
                                                }}
                                                style={{ accentColor: "var(--primary)" }}
                                            />
                                            <span style={{ fontSize: "0.9rem", color: "var(--text)" }}>{cat.name}</span>
                                        </label>
                                    ))}
                                </div>
                            </div>

                            {/* Locations */}
                            <div className="card" style={{ padding: "1.5rem", marginBottom: "1.25rem" }}>
                                <h3 style={{ fontSize: "0.9375rem", fontWeight: 700, marginBottom: "1rem", display: "flex", alignItems: "center", gap: "0.5rem" }}>
                                    <svg width="16" height="16" fill="none" stroke="var(--primary)" strokeWidth="2" viewBox="0 0 24 24">
                                        <path strokeLinecap="round" strokeLinejoin="round" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 0 1-2.827 0l-4.244-4.243a8 8 0 1 1 11.314 0z" />
                                        <path strokeLinecap="round" strokeLinejoin="round" d="M15 11a3 3 0 1 1-6 0 3 3 0 0 1 6 0z" />
                                    </svg>
                                    Địa điểm
                                </h3>
                                {LOCATIONS.map((loc) => (
                                    <label key={loc} style={{ display: "flex", alignItems: "center", gap: "0.5rem", cursor: "pointer", padding: "0.4rem 0" }}>
                                        <input
                                            type="radio"
                                            name="location"
                                            checked={params.loc === loc}
                                            onChange={() => {
                                                const url = new URL(window.location.href);
                                                if (loc === "Remote") {
                                                    url.searchParams.set("loc", loc);
                                                } else {
                                                    url.searchParams.set("loc", loc);
                                                }
                                                window.location.href = url.toString();
                                            }}
                                            style={{ accentColor: "var(--primary)" }}
                                        />
                                        <span style={{ fontSize: "0.9rem", color: "var(--text)" }}>{loc}</span>
                                    </label>
                                ))}
                            </div>

                            {/* Job Types */}
                            <div className="card" style={{ padding: "1.5rem" }}>
                                <h3 style={{ fontSize: "0.9375rem", fontWeight: 700, marginBottom: "1rem", display: "flex", alignItems: "center", gap: "0.5rem" }}>
                                    <svg width="16" height="16" fill="none" stroke="var(--primary)" strokeWidth="2" viewBox="0 0 24 24">
                                        <path strokeLinecap="round" strokeLinejoin="round" d="M21 13.255A23.931 23.931 0 0 1 12 15c-3.183 0-6.22-.62-9-1.745M16 6V4a2 2 0 0 0-2-2h-4a2 2 0 0 0-2 2v2m4 6h.01M5 20h14a2 2 0 0 0 2-2V8a2 2 0 0 0-2-2H5a2 2 0 0 0-2 2v10a2 2 0 0 0 2 2z" />
                                    </svg>
                                    Loại hình
                                </h3>
                                {[
                                    { v: "FULL_TIME", l: "Toàn thời gian" },
                                    { v: "PART_TIME", l: "Bán thời gian" },
                                    { v: "REMOTE", l: "Remote" },
                                    { v: "INTERNSHIP", l: "Thực tập" },
                                    { v: "CONTRACT", l: "Hợp đồng" }
                                ].map((t) => (
                                    <label key={t.v} style={{ display: "flex", alignItems: "center", gap: "0.5rem", cursor: "pointer", padding: "0.4rem 0" }}>
                                        <input
                                            type="radio"
                                            name="type"
                                            checked={params.type === t.v}
                                            onChange={() => {
                                                const url = new URL(window.location.href);
                                                url.searchParams.set("type", t.v);
                                                window.location.href = url.toString();
                                            }}
                                            style={{ accentColor: "var(--primary)" }}
                                        />
                                        <span style={{ fontSize: "0.9rem", color: "var(--text)" }}>{t.l}</span>
                                    </label>
                                ))}
                            </div>
                        </aside>

                        {/* Job list */}
                        <div>
                            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "1.25rem", flexWrap: "wrap", gap: "0.75rem" }}>
                                <p style={{ fontSize: "0.9375rem", color: "var(--text-muted)" }}>
                                    Tìm thấy <strong style={{ color: "var(--primary)" }}>{jobs.length}</strong> việc làm
                                    {currentIndustry && <span> trong ngành <strong>{currentIndustry}</strong></span>}
                                </p>
                                <select style={{ padding: "0.5rem 1rem", borderRadius: "8px", border: "1.5px solid var(--border)", background: "var(--bg-card)", color: "var(--text)", fontFamily: "inherit", fontSize: "0.875rem", cursor: "pointer", outline: "none" }}>
                                    <option>Mới nhất</option>
                                    <option>Lương cao nhất</option>
                                    <option>Lương thấp nhất</option>
                                </select>
                            </div>

                            {jobs.length === 0 ? (
                                <div className="card" style={{ padding: "4rem", textAlign: "center", color: "var(--text-muted)" }}>
                                    <svg width="48" height="48" fill="none" stroke="var(--border)" strokeWidth="1.5" viewBox="0 0 24 24" style={{ margin: "0 auto 1rem" }}>
                                        <circle cx="11" cy="11" r="8" /><path strokeLinecap="round" d="M21 21l-4.35-4.35" />
                                    </svg>
                                    <p style={{ fontWeight: 600 }}>Không tìm thấy việc làm phù hợp</p>
                                    <p style={{ fontSize: "0.875rem", marginTop: "0.5rem" }}>Thử thay đổi từ khóa hoặc bộ lọc</p>
                                </div>
                            ) : (
                                <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(300px, 1fr))", gap: "1.125rem" }}>
                                    {jobs.map((job) => (
                                        <JobCard
                                            key={job.id}
                                            id={job.slug}
                                            title={job.title}
                                            company={job.company.name}
                                            location={job.location}
                                            salary={job.salaryMin && job.salaryMax ? `${Math.round(job.salaryMin / 1000000)}–${Math.round(job.salaryMax / 1000000)} triệu` : "Thỏa thuận"}
                                            type={job.jobType}
                                            skills={job.skills}
                                            posted={new Date(job.createdAt).toLocaleDateString("vi-VN")}
                                            featured={false}
                                        />
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            </main>

            <Footer />
        </div>
    );
}
